   626→	qdisc = nfp_abm_qdisc_find(alink, opt->handle);
   627→	if (!qdisc || !qdisc->offloaded)
   628→		return -EOPNOTSUPP;
   629→
   630→	nfp_abm_stats_red_calculate(&qdisc->red.band[0].xstats,
   631→				    &qdisc->red.band[0].prev_xstats,
   632→				    opt->xstats);
